def _validate_article_payload(body):
    """Validate the request body for article creation.

    Returns (payload_dict, error_response).  On success, error_response is None
    and payload_dict contains 'title' and 'body'.  On failure, returns (None, err_tuple).
    """
    if not isinstance(body, dict):
        return None, _err("Request body must be a JSON object.", 400)

    title = body.get("title")
    body_text = body.get("body")

    if title is None or not isinstance(title, str) or not title.strip():
        return None, _err("Field 'title' is required and must be a non-empty string.", 400)
    if body_text is None or not isinstance(body_text, str) or not body_text.strip():
        return None, _err("Field 'body' is required and must be a non-empty string.", 400)

    return {"title": title.strip(), "body": body_text.strip()}, None


def _fetch_article_or_error(article_id):
    """Look up an article by primary key.

    Returns (article, error_response).  On success, error_response is None.
    On 404, returns (None, error_tuple).
    """
    article = db.session.get(Article, article_id)
    if article is None:
        return None, _err(f"Article {article_id} not found.", 404)
    return article, None


def _create_article_in_db(title, body_text):
    """Persist a new Article and return the serialized result."""
    article = Article(title=title, body=body_text)
    db.session.add(article)
    db.session.commit()
    return _serialize_article(article)


def _list_all_articles():
    """Return serialized list of all articles, ordered by id."""
    articles = Article.query.order_by(Article.id).all()
    return [_serialize_article(a) for a in articles]


def _filter_articles_by_tag_name(tag_name):
    """Filter articles by tag name using explicit JOIN on article_tags.

