        .filter(Tag.name == tag_name)
        .order_by(Article.id)
        .all()
    )
    return [_serialize_article(a) for a in rows]


def _filter_articles_by_tag_id(tag_id):
    """Filter articles by tag ID using explicit JOIN on article_tags.

    Direct association-table query -- no relationship traversal.
