    )
    return [_serialize_article(a) for a in rows]


def _bind_tags_to_article(article, tag_ids):
    """Bind a list of tag IDs to an article via the association table.

    Returns (success_message, error_response).  If any tag_id is invalid,
    no bindings are applied (atomic behavior).
    """
    if not isinstance(tag_ids, list):
        return None, _err("Field 'tag_ids' must be a list of integers.", 400)

    resolved_tags = []
    for tid in tag_ids:
        if not isinstance(tid, int):
            return None, _err(f"Each tag_id must be an integer, got {type(tid).__name__}.", 400)
        tag = db.session.get(Tag, tid)
        if tag is None:
            return None, _err(f"Tag {tid} not found.", 400)
        resolved_tags.append(tag)

    for tag in resolved_tags:
        # Insert only if not already bound (avoid duplicate key errors)
        exists = (
            db.session.query(article_tags)
            .filter_by(article_id=article.id, tag_id=tag.id)
            .first()
